// ─── Loading Step ────────────────────────────────────────────────────────────
function LoadingStep({ title, subtitle, items, activeIndex }) {
  return (
    <div className="flex flex-col items-center gap-8 py-6">
      {/* Animated rings */}
      <div className="relative flex items-center justify-center w-28 h-28">
        <div className="absolute inset-0 rounded-full border-4 border-blue-100" />
        <div className="absolute inset-0 rounded-full border-4 border-transparent border-t-blue-500 animate-spin" />
        <div className="absolute inset-3 rounded-full border-4 border-transparent border-t-blue-300 animate-spin [animation-duration:1.5s] [animation-direction:reverse]" />
        <div className="w-12 h-12 rounded-full bg-blue-600 flex items-center justify-center shadow-lg shadow-blue-200">
          <svg className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M5 12h14M12 5l7 7-7 7" />
          </svg>
        </div>
      </div>

      <div className="text-center space-y-1">
        <h3 className="text-xl font-black text-slate-800 tracking-tight">{title}</h3>
        <p className="text-sm text-slate-500">{subtitle}</p>
      </div>

      {/* Progress items */}
      <div className="w-full max-w-sm space-y-3">
        {items.map((item, i) => (
          <div key={i} className="flex items-center gap-3">
            <div
              className={`w-5 h-5 rounded-full flex items-center justify-center flex-shrink-0 transition-all duration-500 ${
                i < activeIndex
                  ? "bg-blue-600 shadow-md shadow-blue-200"
                  : i === activeIndex
                  ? "bg-blue-100 animate-pulse"
                  : "bg-slate-100"
              }`}
            >
              {i < activeIndex ? (
                <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                </svg>
              ) : i === activeIndex ? (
                <div className="w-2 h-2 rounded-full bg-blue-500 animate-bounce" />
              ) : (
                <div className="w-2 h-2 rounded-full bg-slate-300" />
              )}
            </div>
            <span
              className={`text-sm font-medium transition-colors duration-300 ${
                i < activeIndex ? "text-slate-700" : i === activeIndex ? "text-blue-600" : "text-slate-400"
              }`}
            >
              {item}
            </span>
            {i === activeIndex && (
              <span className="ml-auto text-[10px] font-semibold text-blue-500 animate-pulse">Procesando…</span>
            )}
          </div>
        ))}
      </div>

      {/* Progress bar */}
      <div className="w-full max-w-sm">
        <div className="flex justify-between text-[10px] text-slate-400 mb-1.5 font-medium">
          <span>Progreso</span>
          <span>{Math.round((activeIndex / items.length) * 100)}%</span>
        </div>
        <div className="h-1.5 bg-slate-100 rounded-full overflow-hidden">
          <div
            className="h-full bg-gradient-to-r from-blue-500 to-blue-400 rounded-full transition-all duration-700 ease-out"
            style={{ width: `${(activeIndex / items.length) * 100}%` }}
          />
        </div>
      </div>
    </div>
  );
}

