// ─── Noise / texture overlay ──────────────────────────────────────────────────
const NoiseOverlay = () => (
  <svg className="fixed inset-0 w-full h-full pointer-events-none opacity-[0.025] z-0" xmlns="http://www.w3.org/2000/svg">
    <filter id="noise">
      <feTurbulence type="fractalNoise" baseFrequency="0.65" numOctaves="3" stitchTiles="stitch" />
      <feColorMatrix type="saturate" values="0" />
    </filter>
    <rect width="100%" height="100%" filter="url(#noise)" />
  </svg>
);

// ─── MAIN PAGE ───────────────────────────────────────────────────────────────
export default function TALENTSYNCPage() {
  // ── State (DO NOT MODIFY) ───────────────────────────────────────────────
  const [step, setStep] = useState(STEPS.FORM);
  const [puesto, setPuesto] = useState("");
  const [empresa, setEmpresa] = useState("");
  const [loadingIndex, setLoadingIndex] = useState(0);
  const [cvData, setCvData] = useState(null);
  const [isEditing, setIsEditing] = useState(false);
  const [editData, setEditData] = useState(null);

  // ── Handlers (DO NOT MODIFY logic) ────────────────────────────────────
  const handleGenerate = () => {
    if (!puesto.trim() || !empresa.trim()) return;
    setStep(STEPS.LOADING_RENIEC);
    setLoadingIndex(0);

    const reniecItems = [
      "Conectando con RENIEC…",
      "Verificando DNI…",
      "Extrayendo datos personales…",
      "Validando identidad…",
    ];

    let idx = 0;
    const reniecInterval = setInterval(() => {
      idx++;
      setLoadingIndex(idx);
      if (idx >= reniecItems.length) {
        clearInterval(reniecInterval);
        setTimeout(() => {
          setStep(STEPS.LOADING_MTPE);
          setLoadingIndex(0);
          let idx2 = 0;
          const mtpeInterval = setInterval(() => {
            idx2++;
            setLoadingIndex(idx2);
            if (idx2 >= 4) {
              clearInterval(mtpeInterval);
              setTimeout(() => {
                setCvData(generateMockCV(puesto, empresa));
                setStep(STEPS.CV);
              }, 800);
            }
          }, 900);
        }, 600);
      }
    }, 900);
  };

  const handleEdit = () => {
    setEditData({ ...cvData });
    setIsEditing(true);
  };

  const handleSave = () => {
    setCvData({ ...editData });
    setIsEditing(false);
    setEditData(null);
  };

  const handleCancel = () => {
    setIsEditing(false);
    setEditData(null);
  };

  const handleChange = (key, value) => {
    setEditData((prev) => ({ ...prev, [key]: value }));
  };

  const handleReset = () => {
    setStep(STEPS.FORM);
    setPuesto("");
    setEmpresa("");
    setCvData(null);
    setIsEditing(false);
    setEditData(null);
    setLoadingIndex(0);
  };

  // ── Render ─────────────────────────────────────────────────────────────
  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50/30 to-slate-100 relative overflow-x-hidden">
      <NoiseOverlay />

      {/* Ambient blobs */}
      <div className="fixed top-[-200px] left-[-200px] w-[600px] h-[600px] rounded-full bg-blue-400/10 blur-3xl pointer-events-none z-0" />
      <div className="fixed bottom-[-200px] right-[-200px] w-[500px] h-[500px] rounded-full bg-indigo-400/10 blur-3xl pointer-events-none z-0" />
      <div className="fixed top-1/2 right-[-150px] w-[400px] h-[400px] rounded-full bg-amber-300/5 blur-3xl pointer-events-none z-0" />

      <div className="relative z-10 max-w-2xl mx-auto px-4 py-12">

        {/* ── Header ───────────────────────────────────────────────────── */}
        <header className="text-center mb-10">
          {/* Logo + Brand */}
          <div className="flex flex-col items-center gap-3 mb-5">
            <div className="relative">
              <div className="absolute inset-0 rounded-full bg-blue-400/20 blur-xl scale-150 pointer-events-none" />
              <img
                src={LOGO_B64}
                alt="TalentSync Logo"
                className="relative w-20 h-20 sm:w-24 sm:h-24 object-contain drop-shadow-lg"
              />
            </div>
            <div className="inline-flex items-center gap-2 bg-white/80 backdrop-blur-sm px-4 py-1.5 rounded-full border border-slate-200/80 shadow-sm text-xs font-bold text-blue-600 uppercase tracking-widest">
              <span className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-pulse" />
              Plataforma de Empleabilidad
            </div>
          </div>
          <h1 className="text-4xl sm:text-5xl font-black text-slate-900 tracking-tight leading-none">
            TALENT<span className="text-blue-600">SYNC</span>
          </h1>
          <p className="mt-3 text-slate-500 text-base max-w-sm mx-auto leading-relaxed">
            Genera tu CV ATS-Friendly en segundos sincronizando con bases de datos gubernamentales.
          </p>

          {/* Step badges */}
          {step !== STEPS.FORM && (
            <div className="flex items-center justify-center gap-2 mt-6">
              {["Datos", "RENIEC", "MTPE", "Tu CV"].map((label, i) => (
                <div key={i} className="flex items-center gap-2">
                  <div
                    className={`flex items-center gap-1.5 px-3 py-1 rounded-full text-[11px] font-bold transition-all duration-500 ${
                      i < step
                        ? "bg-blue-600 text-white shadow-md shadow-blue-200"
                        : i === step
                        ? "bg-white border-2 border-blue-500 text-blue-600 shadow-md"
                        : "bg-white/50 border border-slate-200 text-slate-400"
                    }`}
                  >
                    {i < step ? (
                      <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                      </svg>
                    ) : (
                      <span className="w-3.5 h-3.5 rounded-full bg-current opacity-30 inline-block" />
                    )}
                    {label}
                  </div>
                  {i < 3 && <div className={`w-5 h-px ${i < step ? "bg-blue-300" : "bg-slate-200"}`} />}
                </div>
              ))}
            </div>
          )}
        </header>

        {/* ── Main Card ────────────────────────────────────────────────── */}
        <div className="bg-white/70 backdrop-blur-xl rounded-3xl border border-white/80 shadow-xl shadow-slate-200/50 overflow-hidden">

          {/* Step 0 — Form */}
          {step === STEPS.FORM && (
            <div className="p-7 sm:p-9">
              <div className="mb-7">
                <h2 className="text-xl font-black text-slate-800 tracking-tight">Genera tu CV en 30 segundos</h2>
                <p className="text-sm text-slate-500 mt-1">Conectamos con RENIEC y MTPE para completar tu perfil automáticamente.</p>
              </div>

              <div className="space-y-4 mb-6">
                <div className="group">
                  <label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest mb-2">
                    Puesto al que postulas
                  </label>
                  <div className="relative">
                    <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M21 13.255A23.931 23.931 0 0112 15c-3.183 0-6.22-.62-9-1.745M16 6V4a2 2 0 00-2-2h-4a2 2 0 00-2-2v2m8 0H8m8 0a2 2 0 012 2v6a2 2 0 01-2 2H8a2 2 0 01-2-2V8a2 2 0 012-2" />
                      </svg>
                    </div>
                    <input
                      type="text"
                      placeholder="Ej: Ingeniero de Software Senior"
                      value={puesto}
                      onChange={(e) => setPuesto(e.target.value)}
                      className="w-full pl-11 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl text-slate-800 placeholder-slate-400 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-transparent focus:bg-white transition-all duration-200 group-hover:border-slate-300"
                    />
                  </div>
                </div>

                <div className="group">
                  <label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest mb-2">
                    Empresa objetivo
                  </label>
                  <div className="relative">
                    <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-2 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
                      </svg>
                    </div>
                    <input
                      type="text"
                      placeholder="Ej: Minera Antamina S.A.C."
                      value={empresa}
                      onChange={(e) => setEmpresa(e.target.value)}
                      className="w-full pl-11 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl text-slate-800 placeholder-slate-400 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-transparent focus:bg-white transition-all duration-200 group-hover:border-slate-300"
                    />
                  </div>
                </div>
              </div>

              <button
                onClick={handleGenerate}
                disabled={!puesto.trim() || !empresa.trim()}
                className="w-full bg-gradient-to-r from-orange-500 via-orange-500 to-amber-500 text-white font-black py-4 px-8 rounded-2xl transition-all duration-200 shadow-lg shadow-orange-200 hover:shadow-xl hover:shadow-orange-300 hover:-translate-y-0.5 active:translate-y-0 disabled:opacity-40 disabled:cursor-not-allowed disabled:hover:translate-y-0 disabled:shadow-none text-sm tracking-wide flex items-center justify-center gap-2.5"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" />
                </svg>
                Generar CV con IA
              </button>

              {/* Trust badges */}
              <div className="flex items-center justify-center gap-4 mt-5 flex-wrap">
                {["🔒 RENIEC Verificado", "📋 Sync MTPE", "✨ ATS Score 94+"].map((b) => (
                  <span key={b} className="text-[10px] font-semibold text-slate-400">
                    {b}
                  </span>
                ))}
              </div>

              {/* ── Template Gallery ──────────────────────────────────── */}
              <div className="mt-10 pt-8 border-t border-slate-100">
                <div className="flex items-center justify-between mb-5 flex-wrap gap-2">
                  <div>
                    <h3 className="text-base font-black text-slate-800 tracking-tight">Plantillas ATS Premium</h3>
                    <p className="text-xs text-slate-500 mt-0.5">Elige el estilo perfecto para tu perfil</p>
                  </div>
                  <span className="inline-flex items-center gap-1.5 text-[10px] font-bold text-emerald-600 bg-emerald-50 px-3 py-1.5 rounded-full border border-emerald-200">
                    <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M9 12l2 2 4-4M7.835 4.697a3.42 3.42 0 001.946-.806 3.42 3.42 0 014.438 0 3.42 3.42 0 001.946.806 3.42 3.42 0 013.138 3.138 3.42 3.42 0 00.806 1.946 3.42 3.42 0 010 4.438 3.42 3.42 0 00-.806 1.946 3.42 3.42 0 01-3.138 3.138 3.42 3.42 0 00-1.946.806 3.42 3.42 0 01-4.438 0 3.42 3.42 0 00-1.946-.806 3.42 3.42 0 01-3.138-3.138 3.42 3.42 0 00-.806-1.946 3.42 3.42 0 010-4.438 3.42 3.42 0 00.806-1.946 3.42 3.42 0 013.138-3.138z" />
                    </svg>
                    100% Optimizadas para Filtros ATS
                  </span>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                  {TEMPLATES.map((t, i) => (
                    <TemplateCard key={t.id} template={t} index={i} />
                  ))}
                </div>

                <p className="text-center text-[11px] text-slate-400 mt-4">
                  La plantilla se seleccionará automáticamente según tu perfil profesional
                </p>
              </div>
            </div>
          )}

          {/* Step 1 — RENIEC Loading */}
          {step === STEPS.LOADING_RENIEC && (
            <div className="p-7 sm:p-9">
              <LoadingStep
                title="Conectando con RENIEC"
                subtitle="Verificando tu identidad en el Registro Nacional de Identificación…"
                items={[
                  "Iniciando conexión segura SSL/TLS",
                  "Verificando número de DNI",
                  "Extrayendo datos personales oficiales",
                  "Validando firma biométrica",
                ]}
                activeIndex={loadingIndex}
              />
            </div>
          )}

          {/* Step 2 — MTPE Loading */}
          {step === STEPS.LOADING_MTPE && (
            <div className="p-7 sm:p-9">
              <LoadingStep
                title="Sincronizando con MTPE / CertiJoven"
                subtitle="Consultando tus certificaciones laborales y competencias registradas…"
                items={[
                  "Accediendo al portal MTPE",
                  "Recuperando historial laboral formal",
                  "Descargando certificaciones CertiJoven",
                  "Compilando perfil profesional",
                ]}
                activeIndex={loadingIndex}
              />
            </div>
          )}

          {/* Step 3 — CV Result */}
          {step === STEPS.CV && cvData && (
            <div className="p-7 sm:p-9">
              <div className="flex items-center justify-between mb-6">
                <div>
                  <h2 className="text-xl font-black text-slate-800 tracking-tight">
                    {isEditing ? "Editando tu CV" : "Tu CV está listo 🎉"}
                  </h2>
                  <p className="text-xs text-slate-500 mt-0.5">
                    {isEditing
                      ? "Modifica cualquier campo según tu preferencia"
                      : `Generado para: ${empresa}`}
                  </p>
                </div>
                <button
                  onClick={handleReset}
                  className="text-xs font-semibold text-slate-400 hover:text-slate-600 transition-colors flex items-center gap-1.5 px-3 py-1.5 rounded-xl hover:bg-slate-50"
                >
                  <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                  </svg>
                  Nuevo CV
                </button>
              </div>

              <CVDisplay
                cvData={isEditing ? editData : cvData}
                isEditing={isEditing}
                onEdit={handleEdit}
                onSave={handleSave}
                onCancel={handleCancel}
                onChange={handleChange}
              />
            </div>
          )}
        </div>

        {/* Footer */}
        <footer className="text-center mt-8 space-y-1">
          <p className="text-xs text-slate-400 font-medium">
            TALENTSYNC © 2025 — Plataforma de Empleabilidad Estudiantil
          </p>
          <p className="text-[10px] text-slate-300">
            Prototipo académico · Los datos son simulados con fines demostrativos
          </p>
        </footer>
      </div>
    </div>
  );
}

